--

CREATE FUNCTION public.is_rate_type_available_for_area(area_id uuid, rate_type_id uuid) RETURNS boolean
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN EXISTS (
        SELECT 1 FROM area_rate_types 
        WHERE "areaId" = area_id 
          AND "rateTypeId" = rate_type_id 
          AND "isActive" = true
    );
END;
$$;


